mapper.sql:
SELECT w.id, w.warehouse_code, w.warehouse_name, w.warehouse_type, MAX(d.dict_name) AS warehouse_type_name, w.capacity, w.capacity_unit, w.address, w.manager_name, w.manager_phone, w.status, w.remark, w.version, w.temperature_min, w.temperature_max, w.humidity_min, w.humidity_max, w.created_at, w.updated_at, COUNT(l.id) AS position_total, SUM(CASE WHEN l.status = 'occupied' THEN 1 ELSE 0 END) AS position_used, SUM(CASE WHEN l.status = 'available' THEN 1 ELSE 0 END) AS position_idle FROM wms_warehouse w LEFT JOIN sys_dict d ON d.dict_type = 'warehouse_type' AND d.dict_code = w.warehouse_type AND d.tenant_id = w.tenant_id AND d.deleted = 0 LEFT JOIN wms_location l ON l.warehouse_id = w.id AND l.deleted = 0 WHERE w.deleted = 0
AND ( w.warehouse_name LIKE CONCAT('%', #{q.warehouseName}, '%') OR w.warehouse_code LIKE CONCAT('%', #{q.warehouseName}, '%') )
AND w.warehouse_code LIKE CONCAT('%', #{q.warehouseCode}, '%')
AND w.warehouse_name LIKE CONCAT('%', #{q.warehouseName}, '%') AND w.warehouse_code LIKE CONCAT('%', #{q.warehouseCode}, '%')
AND w.warehouse_type = #{q.warehouseType}
AND w.status = #{q.status}
AND w.org_id = #{q.orgId}
AND w.org_id IN
#{orgId}
AND w.id IS NULL
GROUP BY w.id
